<script setup lang="ts">import{ref}from"vue";import{ChevronDown}from"lucide-vue-next";import PageHeader from"../components/PageHeader.vue";const open=ref(0);const items=[['多点执业的医生是否具备与公立医院相同的专业资质？','多点执业医生同样需要完成专业医学教育并取得执业资格，资质认证标准与公立医院医生一致。'],['民营医院的挂号费用与公立医院有何不同？','挂号费用由各医院根据医生职称和服务标准制定，预约页面会显示实际费用。'],['挂号费用是否包含所有诊疗费用？','挂号费通常仅为门诊挂号或初诊咨询费用，检查、药品和治疗费用以医院结算为准。'],['如果预约的医生临时有事，平台会如何处理？','医院变更排班后会尽快通知患者，并协助改约其他时间或医生。'],['预约后是否可以保证医生的出诊时间？','平台展示医院发布的有效排班，临时停诊将以医院最新通知为准。'],['如何管理我的就诊人？','登录后进入“我的”，可在就诊人管理区域查看已保存的就诊人。']];</script><template><main><PageHeader title="常见问题"/><section class="faq-list"><article v-for="(x,i) in items" :key="x[0]" :class="{open:open===i}" @click="open=open===i?-1:i"><header><b>{{String(i+1).padStart(2,'0')}}</b><h2>{{x[0]}}</h2><ChevronDown/></header><p v-if="open===i">{{x[1]}}</p></article></section></main>
</template>
